import xml.etree.ElementTree as ET
def parseXML(file):
    tree = ET.parse(file)
    root = tree.getroot()

    #print(root)
    #print(root.tag, root.attrib)
    #print(root[0].tag, root[0].attrib)

    dict = {}

    def traverse(node):
        for child in node:
            if len(child)==1 and (len(list(child))==2 or len(list(child)) == 3):
                traverse(child)
            else:
                #print(child.tag, child.attrib, child.text)
                dict[str(child)] = str(child.text)
        return

    traverse(root)
    print(dict)

parseXML('test1.xml')

